package bot

import (
	"context"

	"google.golang.org/grpc"
	"google.golang.org/protobuf/types/known/emptypb"

	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/actor/bot"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/grpc/proxyutil"
)

type BotProxy struct {
	bot.UnimplementedBotServer
	client bot.BotClient
}

func init() {
	proxyutil.Register(&bot.Bot_ServiceDesc, NewBotProxy)
}
func NewBotProxy(cc grpc.ClientConnInterface) bot.BotServer {
	return &BotProxy{client: bot.NewBotClient(cc)}
}
func (p *BotProxy) GetCommands(ctx context.Context, in *emptypb.Empty) (*bot.CommandsList, error) {
	return proxyutil.ProxyMethod[emptypb.Empty, bot.CommandsList](p.client.GetCommands)(ctx, in)
}
func (p *BotProxy) OnCommand(ctx context.Context, in *bot.CommandRequest) (*emptypb.Empty, error) {
	return proxyutil.ProxyMethod[bot.CommandRequest, emptypb.Empty](p.client.OnCommand)(ctx, in)
}
